import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './Footer.css';

// Mock API function - replace with your actual API call
const subscribeNewsletter = async (email) => {
  // Simulate API request
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (email && email.includes('@')) {
        console.log('Subscribed:', email);
        resolve();
      } else {
        reject(new Error('Invalid email'));
      }
    }, 500);
  });
};

export default function Footer() {
  const [email, setEmail] = useState('');
  const [subMsg, setSubMsg] = useState('');
  const [isSubscribing, setIsSubscribing] = useState(false);

  const handleSubscribe = async (e) => {
    e.preventDefault();
    if (!email.trim()) return;

    setIsSubscribing(true);
    setSubMsg('');

    try {
      await subscribeNewsletter(email);
      setSubMsg('✓ Subscribed successfully!');
      setEmail('');
    } catch (error) {
      setSubMsg('Please try again with a valid email.');
    } finally {
      setIsSubscribing(false);
    }
  };

  return (
    <footer className="footer">
      <div className="footer-top">
        <div className="container">
          <div className="footer-grid">
            {/* Brand Section */}
            <div className="footer-brand">
              <div className="footer-logo">
                <div className="footer-logo-icon">S</div>
                <div>
                  <div className="footer-logo-name">SHNOOR™</div>
                  <div className="footer-logo-sub">INTERNATIONAL LLC</div>
                </div>
              </div>
              <p>
                Bridging technology and trade across global markets. Your trusted partner 
                for IT solutions and international commerce.
              </p>
              <div className="footer-social">
                <a 
                  href="https://linkedin.com/company/shnoor" 
                  target="_blank" 
                  rel="noreferrer" 
                  aria-label="LinkedIn"
                >
                  in
                </a>
                <a 
                  href="https://wa.me/18165551234" 
                  target="_blank" 
                  rel="noreferrer" 
                  aria-label="WhatsApp"
                >
                  W
                </a>
                <a 
                  href="https://twitter.com/shnoor" 
                  target="_blank" 
                  rel="noreferrer" 
                  aria-label="Twitter"
                >
                  X
                </a>
              </div>
            </div>

            {/* Quick Links */}
            <div className="footer-col">
              <h4>Quick Links</h4>
              <Link to="/">Home</Link>
              <Link to="/about">About Us</Link>
              <Link to="/services">Services</Link>
              <Link to="/logistics">Logistics</Link>
              <Link to="/careers">Careers</Link>
              <Link to="/export">Export Management</Link>
              <Link to="/contact">Contact</Link>
            </div>

            {/* Services */}
            <div className="footer-col">
              <h4>Services</h4>
              <Link to="/services/cloud-management">Cloud Management</Link>
              <Link to="/services/enterprise-management">Enterprise Management</Link>
              <Link to="/services/data-ai">Data & Artificial Intelligence</Link>
              <Link to="/services/it-consulting">Consulting & Staffing</Link>
              <Link to="/services/background-verification">Background Verification</Link>
              <Link to="/services/healthcare">Health Care</Link>
              <Link to="/services/sap-outsourcing">SAP Outsourcing</Link>
            </div>

            {/* Contact & Newsletter */}
            <div className="footer-col">
              <h4>Contact</h4>
              <div className="footer-contact-item">
                <span className="contact-icon">📧</span>
                <div>
                  <a href="mailto:info@shnoor.com">info@shnoor.com</a>
                  <span className="contact-label">General</span>
                </div>
              </div>
              <div className="footer-contact-item">
                <span className="contact-icon">📧</span>
                <div>
                  <a href="mailto:proc@shnoor.com">proc@shnoor.com</a>
                  <span className="contact-label">Sales</span>
                </div>
              </div>
              <div className="footer-contact-item">
                <span className="contact-icon">📍</span>
                <div>
                  <span>10009 Mount Tabor Road,</span>
                  <span>Odessa Missouri, United States</span>
                </div>
              </div>

              <div className="footer-newsletter">
                <h5>Stay Updated</h5>
                <form onSubmit={handleSubscribe} className="newsletter-form">
                  <input
                    type="email"
                    placeholder="Your email address"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    disabled={isSubscribing}
                    required
                  />
                  <button type="submit" disabled={isSubscribing}>
                    {isSubscribing ? '...' : '→'}
                  </button>
                </form>
                {subMsg && <p className="sub-msg">{subMsg}</p>}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Partners Section */}
      <div className="footer-partners">
        <div className="container">
          <span>Our Partners:</span>
          <div className="partners-logos">
            <span className="partner-badge">Google Partner</span>
            <span className="partner-badge">SEMrush</span>
            <span className="partner-badge">HubSpot Diamond</span>
            <span className="partner-badge">Meta Business Partner</span>
          </div>
        </div>
      </div>

      {/* Bottom Bar */}
      <div className="footer-bottom">
        <div className="container">
          <p>© Copyrights 2025. All Rights Reserved. SHNOOR INTERNATIONAL LLC</p>
          <div className="footer-legal">
            <Link to="/privacy">Privacy Policy</Link>
            <Link to="/terms">Terms & Conditions</Link>
            <Link to="/company-profile">Company Profile</Link>
          </div>
        </div>
      </div>
    </footer>
  );
}
